def numberToWords(num):
    if num == 0: return "Zero"
    lt20 = ["","One","Two","Three","Four","Five","Six","Seven","Eight","Nine","Ten","Eleven","Twelve","Thirteen","Fourteen","Fifteen","Sixteen","Seventeen","Eighteen","Nineteen"]
    tens = ["","Ten","Twenty","Thirty","Forty","Fifty","Sixty","Seventy","Eighty","Ninety"]
    thousands = ["","Thousand","Million","Billion"]
    def helper(n):
        if n == 0: return ""
        if n < 20: return lt20[n] + " "
        if n < 100: return tens[n//10] + " " + helper(n%10)
        return lt20[n//100] + " Hundred " + helper(n%100)
    res = ""; bits = 0
    while num > 0:
        if num % 1000 != 0: res = helper(num % 1000) + thousands[bits] + " " + res
        num //= 1000; bits += 1
    return res.strip()

